query:
{
  iamUsers(
    where: {
      AND: [
        {
          hasIAMRole_SOME: {
            OR: [
              { name: { eq: "roles/cloudkms.admin" } }
              { name: { eq: "roles/owner" } }
              { name: { eq: "roles/editor" } }
            ]
          }
        }
        {
          hasIAMRole_SOME: {
            OR: [
              { name: { eq: "roles/cloudkms.cryptoKeyEncrypterDecrypter" } }
              { name: { eq: "roles/cloudkms.cryptoKeyEncrypter" } }
              { name: { eq: "roles/cloudkms.cryptoKeyDecrypter" } }
            ]
          }
        }
      ]
    }
  ) {
    ...AssetFragment
  }
}
